import pytest
import requests

BASE_URL = "http://banking-api/billpay"

def test_billpay_valid_midrange_amount_returns_scheduled(
    auth_headers,        # <fixture>: returns {"Authorization": "Bearer <token>"}
    registered_biller,   # <fixture>: returns {"biller_id": "<id>"}
    funded_account,      # <fixture>: ensures balance >= 500.00
):
    payload = {
        "biller_id": registered_biller["biller_id"],
        "amount": 250.00,
        "currency": "USD",
        "payment_date": "2025-12-01"
    }
    resp = requests.post(BASE_URL, json=payload, headers=auth_headers)
    assert resp.status_code == 201
    body = resp.json()
    assert body["status"] == "SCHEDULED"
    assert body.get("settlement_date") is not None
    assert body.get("payment_id") is not None
